Here's a modern MSTest test class using `MockHttpMessageHandler`, async patterns, and cancellation testing:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com/data");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsNotSuccess()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com/data"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fail-safe so a broken test can't hang CI
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com/data");

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        {
            _content = content;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            var response = new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout guard** | `[Timeout(5000)]` fails the test if it hangs |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **No mocking library** | Subclass `HttpMessageHandler` directly — it's the designed seam for `HttpClient` |
| **`ThrowsExactlyAsync`** | Modern MSTest v3+ assertion; matches the exact exception type (not subclasses) |

> **Tip:** If you're on MSTest v4+, `Assert.ThrowsExactlyAsync` is preferred over the older `Assert.ThrowsExceptionAsync`, which matches subclasses too. Also, all `[TestMethod]` tests in MSTest v3+ support `CancellationToken` injection — you can add a `CancellationToken cancellationToken` parameter to your test method and MSTest will wire it to `[Timeout]` automatically.
